import{_ as e,o as t,c as i,a as s}from"./app.f8e44a68.js";const l="/assets/3c556b84b55209e249f47380ab0a3d34.b4879b18.png",r="/assets/a1226c6af84d80fb618686fa7880e5c7.576edb32.png",p="/assets/af270efc5883a0314de286b88a02a5e7.9ae2e217.png",d="/assets/5d45ee739393b60874aaa0dcd29143f5.394cd08d.png",g=JSON.parse('{"title":"悟道","description":"","frontmatter":{},"headers":[{"level":2,"title":"20 日均线战法（520 战法）","slug":"_20-日均线战法-520-战法","link":"#_20-日均线战法-520-战法","children":[]},{"level":2,"title":"20 日均线战法 选股方法","slug":"_20-日均线战法-选股方法","link":"#_20-日均线战法-选股方法","children":[]}],"relativePath":"note/悟道.md","lastUpdated":1778159364952}'),n={name:"note/悟道.md"};function c(o,a,_,h,f,m){return t(),i("div",{"data-pagefind-body":!0},[...a[0]||(a[0]=[s('<h1 id="悟道" tabindex="-1">悟道 <a class="header-anchor" href="#悟道" aria-hidden="true">#</a></h1><h2 id="_20-日均线战法-520-战法" tabindex="-1">20 日均线战法（520 战法） <a class="header-anchor" href="#_20-日均线战法-520-战法" aria-hidden="true">#</a></h2><p>一般而言，谨慎的投资者会选择在 K 线在 20 日均线上方买入。K 线就像一只小船，漂泊在 20 日 K 线上;如果在下方则小船会翻，预示股价的下跌。</p><p>例如:5 日线上穿 20 日线后的大阳，5 日均线第一个买点 B1 特征就是 5 均线上穿 20 日均线 收涨停或者大阳。大阳当天即可买，这是很重要的中长线买点。</p><p>还有一种买法是 5 日均线上穿 20 日均线后 又出现涨停或者大阳线，5 日线开始向上，大阳后第二天买入，这时候是第二买点 B2。</p><p><img src="'+l+'" alt="alt text"></p><h2 id="_20-日均线战法-选股方法" tabindex="-1">20 日均线战法 选股方法 <a class="header-anchor" href="#_20-日均线战法-选股方法" aria-hidden="true">#</a></h2><p>1、股价向上突破 20 日均线当股价经过一轮下跌后，已经跌无可跌了，股票一定会反弹。当股票经过调整向上突破 20 日均线并且是放量的，这就是技术上的买入点，这里需要注意的一点是要有成交量的配合，否则没有多大的意义。如下图所示，股价快速向上突破 20 日线并且稳稳站住，同时也有成交量放大的配合。当股价有效突破 20 日线后，一般涨幅都不会太小，这时投资者可以大胆买入。</p><p><img src="'+r+'" alt="alt text"></p><p>2、股价在上升趋势中回踩 20 日均线但不跌破 20 日均线 当股价在上升通道中回踩到 20 日线附近时并没有跌破，而且成交量并不大。股份在回调后获得 20 日均线支撑是买入的最好时机。如下图所示，一般在早升通道的股票，它的资金是比较活跃，关注度比较高，当它回调到 20 日均线反弹的机会是非常大的，成功率也是比较高。</p><p><img src="'+p+'" alt="alt text"></p><p>3.股价重新回到 20 日均线股价在上升的过程中，涨幅不是很大。股价跌破正在向上运行的 20 日均线，但是股价很快拉回来，重新站上 20 日均线。这种情况我一般叫他假跌破，般回调时是缩量的，上涨时成交量是方面大。投资者应该在股价重回 20 日均线时买入。</p><p><img src="'+d+'" alt="alt text"></p><p>优势： 它既可避免按 10 日均线交易过于频繁、失误过多、交易成本过高的缺点，又可弥补长周期均线过于滞后的不足。操作方法。是:</p><ol><li>20 日均线在低位走平时关注;</li><li>20 日均线开始向上拐头、股价站上 20 日均线之上时买入，回调确认时加仓;</li><li>均线向上移动一路持有;</li><li>当 20 日均线在高位走平时警惕，一旦收盘时股价跌破 20 日均线立即清仓;</li><li>日后，如果 20 日均线继续上移，股价再次站上 20 日均线时，再买入。</li><li>如此反复操作，直到股价不再创新高并跌破前低，而且，20 日均线调头向下时，结束该股操作。</li><li>在 20 日均线向下移动和横盘整理中，保持空仓观望，耐心等待新一轮上升趋势形成后再择机介入。</li></ol>',15)])])}const u=e(n,[["render",c]]);export{g as __pageData,u as default};
